fn update_clickable_menu(
    backend: &mut dyn Backend,
    changes: &[(&str, &str)],
    events: &[InputEvent],
) -> Option<Menu> {
    backend.render(&mut |fb, stride| {
        for &(name, val) in changes {
            match name {
                "parameter One" => atlas_1().blit(fb, stride, 0, 404,
                    &format!("{:<47}", val)),
                _ => {}
            }
        }
    });
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            if *x < 800 && *y < 120 {
                if let Some(m) = super::function_cl(&[]) { return Some(m); }
            }
            if *x < 800 && *y >= 120 && *y < 240 {
                if let Some(m) = super::function_pr(&["hello"]) { return Some(m); }
            }
            if *x < 800 && *y >= 240 && *y < 360 {
                if let Some(m) = super::fn_multi(&["a", "b"]) { return Some(m); }
            }
            if *x < 800 && *y >= 360 && *y < 480 {
                if let Some(m) = super::fn3(&[]) { return Some(m); }
            }
        }
    }
    None
}

