fn update_widget_menu(
    backend: &mut dyn Backend,
    changes: &[(&str, &str)],
    _events: &[InputEvent],
) -> Option<Menu> {
    backend.render(&mut |fb, stride| {
        for &(name, val) in changes {
            match name {
                "parameter One" => atlas_1().blit(fb, stride, 0, 224,
                    &format!("{:<47}", val)),
                _ => {}
            }
        }
    });
    for &(name, val) in changes {
        if name == "parameter Two" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (800_usize as f32 * v) as usize;
                if filled > 0 {
                    backend.fill_rect(0, 320, filled, 160, rgb!(255, 255, 255));
                }
                if filled < 800 {
                    backend.fill_rect(0 + filled, 320, 800 - filled, 160, rgb!(0, 0, 0));
                }
            }
        }
    }
    None
}

